INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Darkvision', 'Accustomed to life underground, you have superior vision in dark and dim conditions. You can see in dim light within 60 feet of you as if it were bright light, and in darkness as if it were dim light. You can’t discern color in darkness, only shades of gray.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Dwarven Resilience', 'You have advantage on saving throws against poison, and you have resistance against poison damage.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 3, 'Dwarven Combat Training', 'You have proficiency with the battleaxe, handaxe, light hammer, and warhammer.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 4, 'Tool Proficiency', 'You gain proficiency with the artisan’s tools of your choice: smith’s tools, brewer’s supplies, or mason’s tools.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 5, 'Stonecunning', 'Whenever you make an Intelligence (History) check related to the origin of stonework, you are considered proficient in the History skill and add double your proficiency bonus to the check, instead of your normal proficiency bonus.');
