INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (@species_parent, 'Hill Dwarf', NULL, NULL, NULL, 0, 0, 0, 0, 1, 0, 0, 0, NULL, 0, NULL, 'As a hill dwarf, you have keen senses, deep intuition, and remarkable resilience.');
