INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Dwarven Toughness', 'Your hit point maximum increases by 1, and it increases by 1 every time you gain a level.');
INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (NULL, 'Elf', 'Medium', 30, 60, 0, 2, 0, 0, 0, 0, 0, 0, 'Common, Elvish', 0, NULL, 'Your elf character has a variety of natural abilities, the result of thousands of years of elven refinement.

Age: Although elves reach physical maturity at about the same age as humans, the elven understanding of adulthood goes beyond physical growth to encompass worldly experience. An elf typically claims adulthood and an adult name around the age of 100 and can live to be 750 years old.

Alignment: Elves love freedom, variety, and self- expression, so they lean strongly toward the gentler aspects of chaos. They value and protect others’ freedom as well as their own, and they are more often good than not. The drow are an exception; their exile has made them vicious and dangerous. Drow are more often evil than not.');
SET @species_id = LAST_INSERT_ID();
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Darkvision', 'Accustomed to twilit forests and the night sky, you have superior vision in dark and dim conditions. You can see in dim light within 60 feet of you as if it were bright light, and in darkness as if it were dim light. You can’t discern color in darkness, only shades of gray.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Keen Senses', 'You have proficiency in the Perception skill.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 3, 'Fey Ancestry', 'You have advantage on saving throws against being charmed, and magic can’t put you to sleep.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 4, 'Trance', 'Elves don’t need to sleep. Instead, they meditate deeply, remaining semiconscious, for 4 hours a day. (The Common word for such meditation is “trance.”) While meditating, you can dream after a fashion; such dreams are actually mental exercises that have become reflexive through years of practice.

After resting in this way, you gain the same benefit that a human does from 8 hours of sleep.');
SET @species_parent = @species_id;
INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (@species_parent, 'High Elf', NULL, NULL, NULL, 0, 0, 0, 1, 0, 0, 0, 0, NULL, 0, NULL, 'As a high elf, you have a keen mind and a mastery of at least the basics of magic. In many fantasy gaming worlds, there are two kinds of high elves. One type is haughty and reclusive, believing themselves to be superior to non-elves and even other elves. The other type is more common and more friendly, and often encountered among humans and other races.');
SET @species_id = LAST_INSERT_ID();
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Elf Weapon Training', 'You have proficiency with the longsword, shortsword, shortbow, and longbow.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Cantrip', 'You know one cantrip of your choice from the wizard spell list. Intelligence is your spellcasting ability for it.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 3, 'Extra Language', 'You can speak, read, and write one extra language of your choice.');
INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (NULL, 'Halfling', 'Small', 25, NULL, 0, 2, 0, 0, 0, 0, 0, 0, 'Common, Halfling', 0, NULL, 'Your halfling character has a number of traits in common with all other halflings.

Age: A halfling reaches adulthood at the age of 20 and generally lives into the middle of his or her second century.

Alignment: Most halflings are lawful good. As a rule, they are good-hearted and kind, hate to see others in pain, and have no tolerance for oppression. They are also very orderly and traditional, leaning heavily on the support of their community and the comfort of their old ways.');
