INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Lucky', 'When you roll a 1 on the d20 for an attack roll, ability check, or saving throw, you can reroll the die and must use the new roll.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Brave', 'You have advantage on saving throws against being frightened.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 3, 'Halfling Nimbleness', 'You can move through the space of any creature that is of a size larger than yours.');
