INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Naturally Stealthy', 'You can attempt to hide even when you are obscured only by a creature that is at least one size larger than you.');
INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (NULL, 'Human', 'Medium', 30, NULL, 1, 1, 1, 1, 1, 1, 0, 0, 'Common', 1, NULL, 'It’s hard to make generalizations about humans, but your human character has these traits.

