INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (NULL, 'Dragonborn', 'Medium', 30, NULL, 2, 0, 0, 0, 0, 1, 0, 0, 'Common, Draconic', 0, NULL, 'Your draconic heritage manifests in a variety of traits you share with other dragonborn.

Age: Young dragonborn grow quickly. They walk hours after hatching, attain the size and development of a 10-year-old human child by the age of 3, and reach adulthood by 15. They live to be around 80.

Alignment: Dragonborn tend to extremes, making a conscious choice for one side or the other in the cosmic war between good and evil. Most dragonborn are good, but those who side with evil can be terrible villains.');
SET @species_id = LAST_INSERT_ID();
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Draconic Ancestry', 'Black — **Damage Type**: Acid; **Breath Weapon**: 5 by 30 ft. line (Dex. save)
Blue — **Damage Type**: Lightning; **Breath Weapon**: 5 by 30 ft. line (Dex. save)
Brass — **Damage Type**: Fire; **Breath Weapon**: 5 by 30 ft. line (Dex. save)
Bronze — **Damage Type**: Lightning; **Breath Weapon**: 5 by 30 ft. line (Dex. save)
Copper — **Damage Type**: Acid; **Breath Weapon**: 5 by 30 ft. line (Dex. save)
Gold — **Damage Type**: Fire; **Breath Weapon**: 15 ft. cone (Dex. save)
Green — **Damage Type**: Poison; **Breath Weapon**: 15 ft. cone (Con. save)
Red — **Damage Type**: Fire; **Breath Weapon**: 15 ft. cone (Dex. save)
Silver — **Damage Type**: Cold; **Breath Weapon**: 15 ft. cone (Con. save)
White — **Damage Type**: Cold; **Breath Weapon**: 15 ft. cone (Con. save)

You have draconic ancestry. Choose one type of dragon from the Draconic Ancestry table. Your breath weapon and damage resistance are determined by the dragon type, as shown in the table.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Breath Weapon', 'You can use your action to exhale destructive energy. Your draconic ancestry determines the size, shape, and damage type of the exhalation.

When you use your breath weapon, each creature in the area of the exhalation must make a saving throw, the type of which is determined by your draconic ancestry. The DC for this saving throw equals 8 + your Constitution modifier + your proficiency bonus. A creature takes 2d6 damage on a failed save, and half as much damage on a successful one. The damage increases to 3d6 at 6th level, 4d6 at 11th level, and 5d6 at 16th level.

After you use your breath weapon, you can’t use it again until you complete a short or long rest.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 3, 'Damage Resistance', 'You have resistance to the damage type associated with your draconic ancestry.');
INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (NULL, 'Gnome', 'Small', 25, 60, 0, 0, 0, 2, 0, 0, 0, 0, 'Common, Gnomish', 0, NULL, 'Your gnome character has certain characteristics in common with all other gnomes.

Age: Gnomes mature at the same rate humans do, and most are expected to settle down into an adult life by around age 40. They can live 350 to almost 500 years.

Alignment: Gnomes are most often good. Those who tend toward law are sages, engineers, researchers, scholars, investigators, or inventors. Those who tend toward chaos are minstrels, tricksters, wanderers, or fanciful jewelers. Gnomes are good-hearted, and even the tricksters among them are more playful than vicious.');
