INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Artificer’s Lore', 'Whenever you make an Intelligence (History) check related to magic items, alchemical objects, or technological devices, you can add twice your proficiency bonus, instead of any proficiency bonus you normally apply.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Tinker', 'You have proficiency with artisan’s tools (tinker’s tools). Using those tools, you can spend 1 hour and 10 gp worth of materials to construct a Tiny clockwork device (AC 5, 1 hp). The device ceases to function after 24 hours (unless you spend 1 hour repairing it to keep the device functioning), or when you use your action to dismantle it; at that time, you can reclaim the materials used to create it. You can have up to three such devices active at a time.

When you create a device, choose one of the following options:

*Clockwork Toy.* This toy is a clockwork animal, monster, or person, such as a frog, mouse, bird, dragon, or soldier. When placed on the ground, the toy moves 5 feet across the ground on each of your turns in a random direction. It makes noises as appropriate to the creature it represents.
*Fire Starter.* The device produces a miniature flame, which you can use to light a candle, torch, or campfire. Using the device requires your action.
*Music Box.* When opened, this music box plays a single song at a moderate volume. The box stops playing when it reaches the song’s end or when it is closed.');
INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (NULL, 'Half-Elf', 'Medium', 30, 60, 0, 0, 0, 0, 0, 2, 2, 1, 'Common, Elvish', 1, NULL, 'Your half-elf character has some qualities in common with elves and some that are unique to half-elves.

Age: Half-elves mature at the same rate humans do and reach adulthood around the age of 20. They live much longer than humans, however, often exceeding 180 years.

Alignment: Half-elves share the chaotic bent of their elven heritage. They value both personal freedom and creative expression, demonstrating neither love of leaders nor desire for followers. They chafe at rules, resent others’ demands, and sometimes prove unreliable, or at least unpredictable.');
SET @species_id = LAST_INSERT_ID();
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Darkvision', 'Thanks to your elf blood, you have superior vision in dark and dim conditions. You can see in dim light within 60 feet of you as if it were bright light, and in darkness as if it were dim light. You can’t discern color in darkness, only shades of gray.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Fey Ancestry', 'You have advantage on saving throws against being charmed, and magic can’t put you to sleep.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 3, 'Skill Versatility', 'You gain proficiency in two skills of your choice.');
INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (NULL, 'Half-Orc', 'Medium', 30, 60, 2, 0, 1, 0, 0, 0, 0, 0, 'Common, Orc', 0, NULL, 'Your half-orc character has certain traits deriving from your orc ancestry.

Age: Half-orcs mature a little faster than humans, reaching adulthood around age 14. They age noticeably faster and rarely live longer than 75 years.

Alignment: Half-orcs inherit a tendency toward chaos from their orc parents and are not strongly inclined toward good. Half-orcs raised among orcs and willing to live out their lives among them are usually evil.');
SET @species_id = LAST_INSERT_ID();
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Darkvision', 'Thanks to your orc blood, you have superior vision in dark and dim conditions. You can see in dim light within 60 feet of you as if it were bright light, and in darkness as if it were dim light. You can’t discern color in darkness, only shades of gray.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Menacing', 'You gain proficiency in the Intimidation skill.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 3, 'Relentless Endurance', 'When you are reduced to 0 hit points but not killed outright, you can drop to 1 hit point instead. You can’t use this feature again until you finish a long rest.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 4, 'Savage Attacks', 'When you score a critical hit with a melee weapon attack, you can roll one of the weapon’s damage dice one additional time and add it to the extra damage of the critical hit.');
INSERT INTO species (parent_species_id, name, size, speed, darkvision, str_bonus, dex_bonus, con_bonus, int_bonus, wis_bonus, cha_bonus, choice_ability_count, choice_ability_bonus, languages, bonus_language_choice, resistances, description) VALUES (NULL, 'Tiefling', 'Medium', 30, 60, 0, 0, 0, 1, 0, 2, 0, 0, 'Common, Infernal', 0, 'Fire', 'Tieflings share certain racial traits as a result of their infernal descent.

Age: Tieflings mature at the same rate as humans but live a few years longer.

Alignment: Tieflings might not have an innate tendency toward evil, but many of them end up there. Evil or not, an independent nature inclines many tieflings toward a chaotic alignment.');
SET @species_id = LAST_INSERT_ID();
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 1, 'Darkvision', 'Thanks to your infernal heritage, you have superior vision in dark and dim conditions. You can see in dim light within 60 feet of you as if it were bright light, and in darkness as if it were dim light. You can’t discern color in darkness, only shades of gray.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 2, 'Hellish Resistance', 'You have resistance to fire damage.');
INSERT INTO species_traits (species_id, sort_order, name, description) VALUES (@species_id, 3, 'Infernal Legacy', 'You know the *thaumaturgy* cantrip. When you reach 3rd level, you can cast the *hellish rebuke* spell as a 2nd-level spell once with this trait and regain the ability to do so when you finish a long rest. When you reach 5th level, you can cast the *darkness* spell once with this trait and regain the ability to do so when you finish a long rest. Charisma is your spellcasting ability for these spells.');

-- conditions ------------------------------------------------------------
INSERT INTO conditions (name, description) VALUES ('Blinded', 'A blinded creature can’t see and automatically fails any ability check that requires sight.

Attack rolls against the creature have advantage, and the creature’s attack rolls have disadvantage.');
INSERT INTO conditions (name, description) VALUES ('Charmed', 'A charmed creature can’t attack the charmer or target the charmer with harmful abilities or magical effects.

The charmer has advantage on any ability check to interact socially with the creature.');
INSERT INTO conditions (name, description) VALUES ('Deafened', 'A deafened creature can’t hear and automatically fails any ability check that requires hearing.');
INSERT INTO conditions (name, description) VALUES ('Exhaustion', 'Some special abilities and environmental hazards, such as starvation and the long-term effects of freezing or scorching temperatures, can lead to a special condition called exhaustion. Exhaustion is measured in six levels. An effect can give a creature one or more levels of exhaustion, as specified in the effect’s description.

1: Disadvantage on ability checks
2: Speed halved
3: Disadvantage on attack rolls and saving throws
4: Hit point maximum halved
5: Speed reduced to 0
6: Death

If an already exhausted creature suffers another effect that causes exhaustion, its current level of exhaustion increases by the amount specified in the effect’s description.

A creature suffers the effect of its current level of exhaustion as well as all lower levels. For example, a creature suffering level 2 exhaustion has its speed halved and has disadvantage on ability checks.

An effect that removes exhaustion reduces its level as specified in the effect’s description, with all exhaustion effects ending if a creature’s exhaustion level is reduced below 1.

Finishing a long rest reduces a creature’s exhaustion level by 1, provided that the creature has also ingested some food and drink.');
INSERT INTO conditions (name, description) VALUES ('Frightened', 'A frightened creature has disadvantage on ability checks and attack rolls while the source of its fear is within line of sight.

The creature can’t willingly move closer to the source of its fear.');
INSERT INTO conditions (name, description) VALUES ('Grappled', 'A grappled creature’s speed becomes 0, and it can’t benefit from any bonus to its speed.

The condition ends if the grappler is incapacitated (see the condition).

The condition also ends if an effect removes the grappled creature from the reach of the grappler or grappling effect, such as when a creature is hurled away by the *thunder-wave* spell.');
INSERT INTO conditions (name, description) VALUES ('Incapacitated', 'An incapacitated creature can’t take actions or reactions.');
INSERT INTO conditions (name, description) VALUES ('Invisible', 'An invisible creature is impossible to see without the aid of magic or a special sense. For the purpose of hiding, the creature is heavily obscured. The creature’s location can be detected by any noise it makes or any tracks it leaves.

Attack rolls against the creature have disadvantage, and the creature’s attack rolls have advantage.');
INSERT INTO conditions (name, description) VALUES ('Paralyzed', 'A paralyzed creature is incapacitated (see the condition) and can’t move or speak.

The creature automatically fails Strength and Dexterity saving throws.

Attack rolls against the creature have advantage.

Any attack that hits the creature is a critical hit if the attacker is within 5 feet of the creature.');
INSERT INTO conditions (name, description) VALUES ('Petrified', 'A petrified creature is transformed, along with any nonmagical object it is wearing or carrying, into a solid inanimate substance (usually stone). Its weight increases by a factor of ten, and it ceases aging.

The creature is incapacitated (see the condition), can’t move or speak, and is unaware of its surroundings.

Attack rolls against the creature have advantage.

The creature automatically fails Strength and Dexterity saving throws.

The creature has resistance to all damage.

The creature is immune to poison and disease, although a poison or disease already in its system is suspended, not neutralized.');
INSERT INTO conditions (name, description) VALUES ('Poisoned', 'A poisoned creature has disadvantage on attack rolls and ability checks.');
INSERT INTO conditions (name, description) VALUES ('Prone', 'A prone creature’s only movement option is to crawl, unless it stands up and thereby ends the condition.

The creature has disadvantage on attack rolls.

An attack roll against the creature has advantage if the attacker is within 5 feet of the creature. Otherwise, the attack roll has disadvantage.');
INSERT INTO conditions (name, description) VALUES ('Restrained', 'A restrained creature’s speed becomes 0, and it can’t benefit from any bonus to its speed.

Attack rolls against the creature have advantage, and the creature’s attack rolls have disadvantage.

The creature has disadvantage on Dexterity saving throws.');
INSERT INTO conditions (name, description) VALUES ('Stunned', 'A stunned creature is incapacitated (see the condition), can’t move, and can speak only falteringly.

The creature automatically fails Strength and Dexterity saving throws.

Attack rolls against the creature have advantage.');
INSERT INTO conditions (name, description) VALUES ('Unconscious', 'An unconscious creature is incapacitated (see the condition), can’t move or speak, and is unaware of its surroundings

The creature drops whatever it’s holding and falls prone.

The creature automatically fails Strength and Dexterity saving throws.

Attack rolls against the creature have advantage.

Any attack that hits the creature is a critical hit if the attacker is within 5 feet of the creature.');

-- backgrounds ------------------------------------------------------------
INSERT INTO backgrounds (name, description, skill_proficiencies, tool_proficiencies, bonus_language_count, equipment_text, feature_name, feature_description) VALUES ('Acolyte', 'You have spent your life in the service of a temple to a specific god or pantheon of gods. You act as an intermediary between the realm of the holy and the mortal world, performing sacred rites and offering sacrifices in order to conduct worshipers into the presence of the divine. You are not necessarily a cleric—performing sacred rites is not the same thing as channeling divine power.

Choose a god, a pantheon of gods, or some other quasi-divine being from among those listed in "Fantasy-Historical Pantheons" or those specified by your GM, and work with your GM to detail the nature of your religious service. Were you a lesser functionary in a temple, raised from childhood to assist the priests in the sacred rites? Or were you a high priest who suddenly experienced a call to serve your god in a different way? Perhaps you were the leader of a small cult outside of any established temple structure, or even an occult group that served a fiendish master that you now deny.', 'Insight, Religion', NULL, 2, 'A holy symbol (a gift to you when you entered the priesthood), a prayer book or prayer wheel, 5 sticks of incense, vestments, a set of common clothes, and a pouch containing 15 gp', 'Shelter of the Faithful', 'As an acolyte, you command the respect of those who share your faith, and you can perform the religious ceremonies of your deity. You and your adventuring companions can expect to receive free healing and care at a temple, shrine, or other established presence of your faith, though you must provide any material components needed for spells. Those who share your religion will support you (but only you) at a modest lifestyle.

You might also have ties to a specific temple dedicated to your chosen deity or pantheon, and you have a residence there. This could be the temple where you used to serve, if you remain on good terms with it, or a temple where you have found a new home. While near your temple, you can call upon the priests for assistance, provided the assistance you ask for is not hazardous and you remain in good standing with your temple.');
